	public abstract class CameraHistoryItem : ContextItem
	{
		private BufferedRTHandleSystem m_owner;

		private uint m_TypeId = uint.MaxValue;

		protected BufferedRTHandleSystem storage => m_owner;

		public virtual void OnCreate(BufferedRTHandleSystem owner, uint typeId)
		{
			m_owner = owner;
			m_TypeId = typeId;
		}

		protected int MakeId(uint index)
		{
			return (int)(((m_TypeId & 0xFFFF) << 16) | (index & 0xFFFF));
		}

		protected RTHandle AllocHistoryFrameRT(int id, int count, ref RenderTextureDescriptor desc, string name = "")
		{
			return AllocHistoryFrameRT(id, count, ref desc, FilterMode.Bilinear, name);
		}

		protected RTHandle AllocHistoryFrameRT(int id, int count, ref RenderTextureDescriptor desc, FilterMode filterMode, string name = "")
		{
			m_owner.AllocBuffer(id, count, ref desc, filterMode, TextureWrapMode.Clamp, isShadowMap: false, 0, 0f, name);
			return GetCurrentFrameRT(0);
		}

		protected void ReleaseHistoryFrameRT(int id)
		{
			m_owner.ReleaseBuffer(id);
		}

		protected RTHandle GetPreviousFrameRT(int id)
		{
			return m_owner.GetFrameRT(id, 1);
		}

		protected RTHandle GetCurrentFrameRT(int id)
		{
			return m_owner.GetFrameRT(id, 0);
		}
	}
	public class CameraSwitcher : MonoBehaviour
	{
		public Camera[] m_Cameras;

		private int m_CurrentCameraIndex = -1;

		private Camera m_OriginalCamera;

		private Vector3 m_OriginalCameraPosition;

		private Quaternion m_OriginalCameraRotation;

		private Camera m_CurrentCamera;

		private GUIContent[] m_CameraNames;

		private int[] m_CameraIndices;

		private DebugUI.EnumField m_DebugEntry;

		private int m_DebugEntryEnumIndex;

		private void OnEnable()
		{
			m_OriginalCamera = GetComponent<Camera>();
			m_CurrentCamera = m_OriginalCamera;
			if (m_OriginalCamera == null)
			{
				Debug.LogError("Camera Switcher needs a Camera component attached");
				return;
			}
			m_CurrentCameraIndex = GetCameraCount() - 1;
			m_CameraNames = new GUIContent[GetCameraCount()];
			m_CameraIndices = new int[GetCameraCount()];
			for (int i = 0; i < m_Cameras.Length; i++)
			{
				Camera camera = m_Cameras[i];
				if (camera != null)
				{
					m_CameraNames[i] = new GUIContent(camera.name);
				}
				else
				{
					m_CameraNames[i] = new GUIContent("null");
				}
				m_CameraIndices[i] = i;
			}
			m_CameraNames[GetCameraCount() - 1] = new GUIContent("Original Camera");
			m_CameraIndices[GetCameraCount() - 1] = GetCameraCount() - 1;
			m_DebugEntry = new DebugUI.EnumField
			{
				displayName = "Camera Switcher",
				getter = () => m_CurrentCameraIndex,
				setter = delegate(int value)
				{
					SetCameraIndex(value);
				},
				enumNames = m_CameraNames,
				enumValues = m_CameraIndices,
				getIndex = () => m_DebugEntryEnumIndex,
				setIndex = delegate(int value)
				{
					m_DebugEntryEnumIndex = value;
				}
			};
			DebugManager.instance.GetPanel("Camera", createIfNull: true).children.Add(m_DebugEntry);
		}

		private void OnDisable()
		{
			if (m_DebugEntry != null && m_DebugEntry.panel != null)
			{
				m_DebugEntry.panel.children.Remove(m_DebugEntry);
			}
		}

		private int GetCameraCount()
		{
			return m_Cameras.Length + 1;
		}

		private Camera GetNextCamera()
		{
			if (m_CurrentCameraIndex == m_Cameras.Length)
			{
				return m_OriginalCamera;
			}
			return m_Cameras[m_CurrentCameraIndex];
		}

		private void SetCameraIndex(int index)
		{
			if (index <= 0 || index >= GetCameraCount())
			{
				return;
			}
			m_CurrentCameraIndex = index;
			if (m_CurrentCamera == m_OriginalCamera)
			{
				m_OriginalCameraPosition = m_OriginalCamera.transform.position;
				m_OriginalCameraRotation = m_OriginalCamera.transform.rotation;
			}
			m_CurrentCamera = GetNextCamera();
			if (m_CurrentCamera != null)
			{
				if (m_CurrentCamera == m_OriginalCamera)
				{
					m_OriginalCamera.transform.SetPositionAndRotation(m_OriginalCameraPosition, m_OriginalCameraRotation);
				}
				base.transform.SetPositionAndRotation(m_CurrentCamera.transform.position, m_CurrentCamera.transform.rotation);
			}
		}
	}
	public class FreeCamera : MonoBehaviour
	{
		private const float k_MouseSensitivityMultiplier = 0.01f;

		public float m_LookSpeedController = 120f;

		public float m_LookSpeedMouse = 4f;

		public float m_MoveSpeed = 10f;

		public float m_MoveSpeedIncrement = 2.5f;

		public float m_Turbo = 10f;

		private InputAction lookAction;

		private InputAction moveAction;

		private InputAction speedAction;

		private InputAction yMoveAction;

		private float inputRotateAxisX;

		private float inputRotateAxisY;

		private float inputChangeSpeed;

		private float inputVertical;

		private float inputHorizontal;

		private float inputYAxis;

		private bool leftShiftBoost;

		private bool leftShift;

		private bool fire1;

		private void OnEnable()
		{
			RegisterInputs();
		}

		private void RegisterInputs()
		{
			InputActionMap map = new InputActionMap("Free Camera");
			lookAction = map.AddAction("look", InputActionType.Value, "<Mouse>/delta");
			moveAction = map.AddAction("move", InputActionType.Value, "<Gamepad>/leftStick");
			speedAction = map.AddAction("speed", InputActionType.Value, "<Gamepad>/dpad");
			yMoveAction = map.AddAction("yMove");
			lookAction.AddBinding("<Gamepad>/rightStick").WithProcessor("scaleVector2(x=15, y=15)");
			moveAction.AddCompositeBinding("Dpad").With("Up", "<Keyboard>/w").With("Up", "<Keyboard>/upArrow")
				.With("Down", "<Keyboard>/s")
				.With("Down", "<Keyboard>/downArrow")
				.With("Left", "<Keyboard>/a")
				.With("Left", "<Keyboard>/leftArrow")
				.With("Right", "<Keyboard>/d")
				.With("Right", "<Keyboard>/rightArrow");
			speedAction.AddCompositeBinding("Dpad").With("Up", "<Keyboard>/home").With("Down", "<Keyboard>/end");
			yMoveAction.AddCompositeBinding("Dpad").With("Up", "<Keyboard>/pageUp").With("Down", "<Keyboard>/pageDown")
				.With("Up", "<Keyboard>/e")
				.With("Down", "<Keyboard>/q")
				.With("Up", "<Gamepad>/rightshoulder")
				.With("Down", "<Gamepad>/leftshoulder");
			moveAction.Enable();
			lookAction.Enable();
			speedAction.Enable();
			yMoveAction.Enable();
		}

		private void UpdateInputs()
		{
			inputRotateAxisX = 0f;
			inputRotateAxisY = 0f;
			leftShiftBoost = false;
			fire1 = false;
			Vector2 vector = lookAction.ReadValue<Vector2>();
			inputRotateAxisX = vector.x * m_LookSpeedMouse * 0.01f;
			inputRotateAxisY = vector.y * m_LookSpeedMouse * 0.01f;
			leftShift = Keyboard.current?.leftShiftKey?.isPressed == true;
			Mouse current = Mouse.current;
			int num;
			if (current == null || current.leftButton?.isPressed != true)
			{
				Gamepad current2 = Gamepad.current;
				num = ((current2 != null && current2.xButton?.isPressed == true) ? 1 : 0);
			}
			else
			{
				num = 1;
			}
			fire1 = (byte)num != 0;
			inputChangeSpeed = speedAction.ReadValue<Vector2>().y;
			Vector2 vector2 = moveAction.ReadValue<Vector2>();
			inputVertical = vector2.y;
			inputHorizontal = vector2.x;
			inputYAxis = yMoveAction.ReadValue<Vector2>().y;
		}

		private void Update()
		{
			if (DebugManager.instance.displayRuntimeUI)
			{
				return;
			}
			UpdateInputs();
			if (inputChangeSpeed != 0f)
			{
				m_MoveSpeed += inputChangeSpeed * m_MoveSpeedIncrement;
				if (m_MoveSpeed < m_MoveSpeedIncrement)
				{
					m_MoveSpeed = m_MoveSpeedIncrement;
				}
			}
			if (inputRotateAxisX != 0f || inputRotateAxisY != 0f || inputVertical != 0f || inputHorizontal != 0f || inputYAxis != 0f)
			{
				float x = base.transform.localEulerAngles.x;
				float y = base.transform.localEulerAngles.y + inputRotateAxisX;
				float num = x - inputRotateAxisY;
				if (x <= 90f && num >= 0f)
				{
					num = Mathf.Clamp(num, 0f, 90f);
				}
				if (x >= 270f)
				{
					num = Mathf.Clamp(num, 270f, 360f);
				}
				base.transform.localRotation = Quaternion.Euler(num, y, base.transform.localEulerAngles.z);
				float num2 = Time.deltaTime * m_MoveSpeed;
				if (fire1 || (leftShiftBoost && leftShift))
				{
					num2 *= m_Turbo;
				}
				base.transform.position += base.transform.forward * (num2 * inputVertical) + base.transform.right * (num2 * inputHorizontal) + Vector3.up * (num2 * inputYAxis);
			}
		}
	}
	public class BaseCommandBuffer
	{
		protected internal CommandBuffer m_WrappedCommandBuffer;

		internal RenderGraphPass m_ExecutingPass;

		public string name => m_WrappedCommandBuffer.name;

		public int sizeInBytes => m_WrappedCommandBuffer.sizeInBytes;

		internal BaseCommandBuffer(CommandBuffer wrapped, RenderGraphPass executingPass, bool isAsync)
		{
			m_WrappedCommandBuffer = wrapped;
			m_ExecutingPass = executingPass;
			if (isAsync)
			{
				m_WrappedCommandBuffer.SetExecutionFlags(CommandBufferExecutionFlags.AsyncCompute);
			}
		}

		[Conditional("DEVELOPMENT_BUILD")]
		[Conditional("UNITY_EDITOR")]
		protected internal void ThrowIfGlobalStateNotAllowed()
		{
			if (m_ExecutingPass != null && !m_ExecutingPass.allowGlobalState)
			{
				throw new InvalidOperationException(m_ExecutingPass.name + ": Modifying global state from this command buffer is not allowed. Please ensure your render graph pass allows modifying global state.");
			}
		}

		[Conditional("DEVELOPMENT_BUILD")]
		[Conditional("UNITY_EDITOR")]
		protected internal void ThrowIfRasterNotAllowed()
		{
			if (m_ExecutingPass != null && !m_ExecutingPass.HasRenderAttachments())
			{
				throw new InvalidOperationException(m_ExecutingPass.name + ": Using raster commands from a pass with no active render target is not allowed as it will use an undefined render target state. Please set up pass render targets using SetRenderAttachments.");
			}
		}

		[Conditional("DEVELOPMENT_BUILD")]
		[Conditional("UNITY_EDITOR")]
		protected internal void ValidateTextureHandle(TextureHandle h)
		{
			if (RenderGraph.enableValidityChecks && m_ExecutingPass != null && !h.IsBuiltin())
			{
				if (!m_ExecutingPass.IsRead(in h.handle) && !m_ExecutingPass.IsWritten(in h.handle) && !m_ExecutingPass.IsTransient(in h.handle))
				{
					throw new Exception("Pass '" + m_ExecutingPass.name + "' is trying to bind a texture on the command buffer that is not registered by its builder. Please indicate to the pass builder how the texture is used (UseTexture/CreateTransientTexture).");
				}
				if (m_ExecutingPass.IsAttachment(in h))
				{
					throw new Exception("Pass '" + m_ExecutingPass.name + "' is trying to bind a texture on the command buffer that is already set as a fragment attachment (SetRenderAttachment/SetRenderAttachmentDepth). A texture cannot be used as both in one pass, please fix its usage in the pass builder.");
				}
			}
		}

		[Conditional("DEVELOPMENT_BUILD")]
		[Conditional("UNITY_EDITOR")]
		protected internal void ValidateTextureHandleRead(TextureHandle h)
		{
			if (RenderGraph.enableValidityChecks && m_ExecutingPass != null)
			{
				if (!m_ExecutingPass.IsRead(in h.handle) && !m_ExecutingPass.IsTransient(in h.handle))
				{
					throw new Exception("Pass '" + m_ExecutingPass.name + "' is trying to read a texture on the command buffer that is not registered by its builder. Please indicate to the pass builder that the texture is read (UseTexture/CreateTransientTexture).");
				}
				if (m_ExecutingPass.IsAttachment(in h))
				{
					throw new Exception("Pass '" + m_ExecutingPass.name + "' is trying to bind a texture on the command buffer that is already set as a fragment attachment (SetRenderAttachment/SetRenderAttachmentDepth). A texture cannot be used as both in one pass, please fix its usage in the pass builder.");
				}
			}
		}

		[Conditional("DEVELOPMENT_BUILD")]
		[Conditional("UNITY_EDITOR")]
		protected internal void ValidateTextureHandleWrite(TextureHandle h)
		{
			if (RenderGraph.enableValidityChecks && m_ExecutingPass != null)
			{
				if (h.IsBuiltin())
				{
					throw new Exception("Pass '" + m_ExecutingPass.name + "' is trying to write to a built-in texture. This is not allowed built-in textures are small default resources like `white` or `black` that cannot be written to.");
				}
				if (!m_ExecutingPass.IsWritten(in h.handle) && !m_ExecutingPass.IsTransient(in h.handle))
				{
					throw new Exception("Pass '" + m_ExecutingPass.name + "' is trying to write a texture on the command buffer that is not registered by its builder. Please indicate to the pass builder that the texture is written (UseTexture/CreateTransientTexture).");
				}
				if (m_ExecutingPass.IsAttachment(in h))
				{
					throw new Exception("Pass '" + m_ExecutingPass.name + "' is trying to bind a texture on the command buffer that is already set as a fragment attachment (SetRenderAttachment/SetRenderAttachmentDepth). A texture cannot be used as both in one pass, please fix its usage in the pass builder.");
				}
			}
		}
	}
