			{
				return opened;
			}

			object IValueField.GetValue()
			{
				return GetValue();
			}

			public void SetValue(object value)
			{
				SetValue((bool)value);
			}

			public object ValidateValue(object value)
			{
				return value;
			}

			public void SetValue(bool value)
			{
				opened = value;
			}
