			public uint intStepMult = 10u;

			public override uint ValidateValue(uint value)
			{
				if (min != null)
				{
					value = (uint)Mathf.Max((int)value, (int)min());
				}
				if (max != null)
				{
					value = (uint)Mathf.Min((int)value, (int)max());
				}
				return value;
			}
		}

