					}
				}
				m_CurrentBuffer = 0;
				stagingBuffer = new NativeArray<byte>(num * 4, Allocator.Persistent);
			}

			public void Swap()
			{
				m_CurrentBuffer = (m_CurrentBuffer + 1) % 2;
			}

			public void Dispose()
			{
				for (int i = 0; i < 2; i++)
				{
					m_GraphicsBuffers[i]?.Dispose();
				}
				stagingBuffer.Dispose();
			}
