					}
				}
				hashSet.Remove(m_CurrentBakingSet.lightingScenario);
				if (!(m_DebugActiveSceneGUID == guid) || hashSet.Count + 1 != m_DebugScenarioNames.Length || !(m_DebugActiveScenario == m_CurrentBakingSet.lightingScenario))
				{
					int num = 0;
