			NativeArray<byte> nativeArray = RequestScratchBuffer(num);
			num2 = 0;
			long num3 = 0L;
			byte* unsafePtr = (byte*)nativeArray.GetUnsafePtr();
			foreach (int cellIndex2 in cellIndices)
