			m_ReadCommandArray.ReadCommands = (ReadCommand*)m_ReadCommandBuffer.GetUnsafePtr();
			ReadHandle readHandle = AsyncReadManager.Read(asset.OpenFile(), m_ReadCommandArray);
			readHandle.JobHandle.Complete();
