		private static readonly int s_hammersley2DSeq16Id = Shader.PropertyToID("Hammersley2dSeq16");

		private static readonly int s_hammersley2DSeq32Id = Shader.PropertyToID("Hammersley2dSeq32");

		private static readonly int s_hammersley2DSeq64Id = Shader.PropertyToID("Hammersley2dSeq64");

		private static readonly int s_hammersley2DSeq256Id = Shader.PropertyToID("Hammersley2dSeq256");

		public unsafe static void Initialize()
		{
			Hammersley2dSeq16 data = default(Hammersley2dSeq16);
			Hammersley2dSeq32 data2 = default(Hammersley2dSeq32);
			Hammersley2dSeq64 data3 = default(Hammersley2dSeq64);
			Hammersley2dSeq256 data4 = default(Hammersley2dSeq256);
			for (int i = 0; i < k_Hammersley2dSeq16.Length; i++)
			{
				data.hammersley2dSeq16[i] = k_Hammersley2dSeq16[i];
			}
			for (int j = 0; j < k_Hammersley2dSeq32.Length; j++)
			{
				data2.hammersley2dSeq32[j] = k_Hammersley2dSeq32[j];
			}
			for (int k = 0; k < k_Hammersley2dSeq64.Length; k++)
			{
				data3.hammersley2dSeq64[k] = k_Hammersley2dSeq64[k];
			}
			for (int l = 0; l < k_Hammersley2dSeq256.Length; l++)
			{
				data4.hammersley2dSeq256[l] = k_Hammersley2dSeq256[l];
			}
			ConstantBuffer.UpdateData(in data);
			ConstantBuffer.UpdateData(in data2);
			ConstantBuffer.UpdateData(in data3);
			ConstantBuffer.UpdateData(in data4);
		}

		public static void BindConstants(CommandBuffer cmd, ComputeShader cs)
		{
			ConstantBuffer.Set<Hammersley2dSeq16>(cmd, cs, s_hammersley2DSeq16Id);
			ConstantBuffer.Set<Hammersley2dSeq32>(cmd, cs, s_hammersley2DSeq32Id);
			ConstantBuffer.Set<Hammersley2dSeq64>(cmd, cs, s_hammersley2DSeq64Id);
			ConstantBuffer.Set<Hammersley2dSeq256>(cmd, cs, s_hammersley2DSeq256Id);
		}
	}
	public interface ISTPEnabledRenderPipeline
	{
		bool isStpUsed { get; }
	}
	public static class STP
	{
		public struct PerViewConfig
		{
			public Matrix4x4 currentProj;

			public Matrix4x4 lastProj;

			public Matrix4x4 lastLastProj;

			public Matrix4x4 currentView;

			public Matrix4x4 lastView;

			public Matrix4x4 lastLastView;
		}

		public struct Config
		{
			public Texture2D noiseTexture;

			public TextureHandle inputColor;

			public TextureHandle inputDepth;

			public TextureHandle inputMotion;

			public TextureHandle inputStencil;

			public TextureHandle debugView;

			public TextureHandle destination;

			public HistoryContext historyContext;

			public bool enableHwDrs;

			public bool enableTexArray;

			public bool enableMotionScaling;

			public float nearPlane;

			public float farPlane;

			public int frameIndex;

			public bool hasValidHistory;

			public int stencilMask;

			public int debugViewIndex;

			public float deltaTime;

			public float lastDeltaTime;

			public Vector2Int currentImageSize;

			public Vector2Int priorImageSize;

			public Vector2Int outputImageSize;

			public int numActiveViews;

			public PerViewConfig[] perViewConfigs;
		}

		internal enum HistoryTextureType
		{
			DepthMotion,
			Luma,
			Convergence,
			Feedback,
			Count
		}

		public struct HistoryUpdateInfo
		{
			public Vector2Int preUpscaleSize;

			public Vector2Int postUpscaleSize;

			public bool useHwDrs;

			public bool useTexArray;
		}

		public sealed class HistoryContext : IDisposable
		{
			private RTHandle[] m_textures = new RTHandle[8];

			private Hash128 m_hash = Hash128.Compute(0);

			public bool Update(ref HistoryUpdateInfo info)
			{
				bool result = true;
				Hash128 hash = ComputeHistoryHash(ref info);
				if (hash != m_hash)
				{
					result = false;
					Dispose();
					m_hash = hash;
					Vector2Int historyTextureSize = (info.useHwDrs ? info.postUpscaleSize : info.preUpscaleSize);
					TextureDimension dimension = (info.useTexArray ? TextureDimension.Tex2DArray : TextureDimension.Tex2D);
					int slices = ((!info.useTexArray) ? 1 : TextureXR.slices);
					int num = 0;
					int num2 = 0;
					GraphicsFormat graphicsFormat = GraphicsFormat.None;
					bool useDynamicScaleExplicit = false;
					string text = "";
