		private void ClearCompiledGraph(CompiledGraph compiledGraph, bool useCompilationCaching)
		{
			ClearRenderPasses();
			m_Resources.Clear(m_ExecutionExceptionWasRaised);
			m_RendererLists.Clear();
			registeredGlobals.Clear();
