	[MovedFrom(true, "UnityEngine.Experimental.Rendering.RenderGraphModule", "UnityEngine.Rendering.RenderGraphModule", null)]
	public class RenderGraphDefaultResources
	{
		private RTHandle m_BlackTexture2D;

		private RTHandle m_WhiteTexture2D;

		private RTHandle m_ShadowTexture2D;

		public TextureHandle blackTexture { get; private set; }

		public TextureHandle whiteTexture { get; private set; }

		public TextureHandle clearTextureXR { get; private set; }

		public TextureHandle magentaTextureXR { get; private set; }

		public TextureHandle blackTextureXR { get; private set; }

		public TextureHandle blackTextureArrayXR { get; private set; }

		public TextureHandle blackUIntTextureXR { get; private set; }

		public TextureHandle blackTexture3DXR { get; private set; }

		public TextureHandle whiteTextureXR { get; private set; }

		public TextureHandle defaultShadowTexture { get; private set; }

		internal RenderGraphDefaultResources()
		{
			InitDefaultResourcesIfNeeded();
		}

		private void InitDefaultResourcesIfNeeded()
		{
			if (m_BlackTexture2D == null)
			{
				m_BlackTexture2D = RTHandles.Alloc(Texture2D.blackTexture);
			}
			if (m_WhiteTexture2D == null)
			{
				m_WhiteTexture2D = RTHandles.Alloc(Texture2D.whiteTexture);
			}
			if (m_ShadowTexture2D == null)
			{
				m_ShadowTexture2D = RTHandles.Alloc(1, 1, CoreUtils.GetDefaultDepthOnlyFormat(), 1, FilterMode.Point, TextureWrapMode.Repeat, TextureDimension.Tex2D, enableRandomWrite: false, useMipMap: false, autoGenerateMips: true, isShadowMap: true, 1, 0f, MSAASamples.None, bindTextureMS: false, useDynamicScale: false, useDynamicScaleExplicit: false, RenderTextureMemoryless.None, VRTextureUsage.None, "DefaultShadowTexture");
				CommandBuffer commandBuffer = CommandBufferPool.Get();
				commandBuffer.SetRenderTarget(m_ShadowTexture2D);
				commandBuffer.ClearRenderTarget(RTClearFlags.All, Color.white);
				Graphics.ExecuteCommandBuffer(commandBuffer);
				CommandBufferPool.Release(commandBuffer);
			}
		}

		internal void Cleanup()
		{
			m_BlackTexture2D?.Release();
			m_BlackTexture2D = null;
			m_WhiteTexture2D?.Release();
			m_WhiteTexture2D = null;
			m_ShadowTexture2D?.Release();
			m_ShadowTexture2D = null;
		}

		internal void InitializeForRendering(RenderGraph renderGraph)
		{
			InitDefaultResourcesIfNeeded();
			blackTexture = renderGraph.ImportTexture(m_BlackTexture2D, isBuiltin: true);
			whiteTexture = renderGraph.ImportTexture(m_WhiteTexture2D, isBuiltin: true);
			defaultShadowTexture = renderGraph.ImportTexture(m_ShadowTexture2D, isBuiltin: true);
			clearTextureXR = renderGraph.ImportTexture(TextureXR.GetClearTexture(), isBuiltin: true);
			magentaTextureXR = renderGraph.ImportTexture(TextureXR.GetMagentaTexture(), isBuiltin: true);
			blackTextureXR = renderGraph.ImportTexture(TextureXR.GetBlackTexture(), isBuiltin: true);
			blackTextureArrayXR = renderGraph.ImportTexture(TextureXR.GetBlackTextureArray(), isBuiltin: true);
			blackUIntTextureXR = renderGraph.ImportTexture(TextureXR.GetBlackUIntTexture(), isBuiltin: true);
			blackTexture3DXR = renderGraph.ImportTexture(TextureXR.GetBlackTexture3D(), isBuiltin: true);
			whiteTextureXR = renderGraph.ImportTexture(TextureXR.GetWhiteTexture(), isBuiltin: true);
		}
	}
	internal struct RenderGraphLogIndent : IDisposable
	{
		private int m_Indentation;

		private RenderGraphLogger m_Logger;

		private bool m_Disposed;

		public RenderGraphLogIndent(RenderGraphLogger logger, int indentation = 1)
		{
			m_Disposed = false;
			m_Indentation = indentation;
			m_Logger = logger;
			m_Logger.IncrementIndentation(m_Indentation);
		}

		public void Dispose()
		{
			Dispose(disposing: true);
		}

		private void Dispose(bool disposing)
		{
			if (!m_Disposed)
			{
				if (disposing && m_Logger != null)
				{
					m_Logger.DecrementIndentation(m_Indentation);
				}
				m_Disposed = true;
			}
		}
	}
	internal class RenderGraphLogger
	{
		private Dictionary<string, StringBuilder> m_LogMap = new Dictionary<string, StringBuilder>();

		private StringBuilder m_CurrentBuilder;

		private int m_CurrentIndentation;

		public void Initialize(string logName)
		{
			if (!m_LogMap.TryGetValue(logName, out var value))
			{
				value = new StringBuilder();
				m_LogMap.Add(logName, value);
			}
			m_CurrentBuilder = value;
			m_CurrentBuilder.Clear();
			m_CurrentIndentation = 0;
		}

		public void IncrementIndentation(int value)
		{
			m_CurrentIndentation += Math.Abs(value);
		}

		public void DecrementIndentation(int value)
		{
			m_CurrentIndentation = Math.Max(0, m_CurrentIndentation - Math.Abs(value));
		}

		public void LogLine(string format, params object[] args)
		{
			for (int i = 0; i < m_CurrentIndentation; i++)
			{
				m_CurrentBuilder.Append('\t');
			}
			m_CurrentBuilder.AppendFormat(format, args);
			m_CurrentBuilder.AppendLine();
		}

		public void FlushLogs()
		{
			string text = "";
			foreach (KeyValuePair<string, StringBuilder> item in m_LogMap)
			{
				StringBuilder value = item.Value;
				value.AppendLine();
				text += value.ToString();
			}
			m_LogMap.Clear();
			Debug.Log(text);
		}
	}
	public sealed class RenderGraphObjectPool
	{
		private class SharedObjectPoolBase
		{
			public virtual void Clear()
			{
			}
		}

		private class SharedObjectPool<T> : SharedObjectPoolBase where T : class, new()
		{
			private static readonly UnityEngine.Pool.ObjectPool<T> s_Pool = AllocatePool();

			private static UnityEngine.Pool.ObjectPool<T> AllocatePool()
			{
				UnityEngine.Pool.ObjectPool<T> result = new UnityEngine.Pool.ObjectPool<T>(() => new T());
				s_AllocatedPools.Add((SharedObjectPoolBase)new SharedObjectPool<T>());
				return result;
			}

			public override void Clear()
			{
				s_Pool.Clear();
			}

			public static T Get()
			{
				return s_Pool.Get();
			}

			public static void Release(T toRelease)
			{
				s_Pool.Release(toRelease);
			}
		}

		private static DynamicArray<SharedObjectPoolBase> s_AllocatedPools = new DynamicArray<SharedObjectPoolBase>();

		private Dictionary<(Type, int), Stack<object>> m_ArrayPool = new Dictionary<(Type, int), Stack<object>>();

		private List<(object, (Type, int))> m_AllocatedArrays = new List<(object, (Type, int))>();

		private List<MaterialPropertyBlock> m_AllocatedMaterialPropertyBlocks = new List<MaterialPropertyBlock>();

		internal RenderGraphObjectPool()
		{
		}

		public T[] GetTempArray<T>(int size)
		{
			if (!m_ArrayPool.TryGetValue((typeof(T), size), out var value))
			{
				value = new Stack<object>();
				m_ArrayPool.Add((typeof(T), size), value);
			}
			T[] array = ((value.Count > 0) ? ((T[])value.Pop()) : new T[size]);
			m_AllocatedArrays.Add((array, (typeof(T), size)));
			return array;
		}

		public MaterialPropertyBlock GetTempMaterialPropertyBlock()
		{
			MaterialPropertyBlock materialPropertyBlock = SharedObjectPool<MaterialPropertyBlock>.Get();
			materialPropertyBlock.Clear();
			m_AllocatedMaterialPropertyBlocks.Add(materialPropertyBlock);
			return materialPropertyBlock;
		}

		internal void ReleaseAllTempAlloc()
		{
			foreach (var allocatedArray in m_AllocatedArrays)
			{
				m_ArrayPool.TryGetValue(allocatedArray.Item2, out var value);
				value.Push(allocatedArray.Item1);
			}
			m_AllocatedArrays.Clear();
			foreach (MaterialPropertyBlock allocatedMaterialPropertyBlock in m_AllocatedMaterialPropertyBlocks)
			{
				SharedObjectPool<MaterialPropertyBlock>.Release(allocatedMaterialPropertyBlock);
			}
			m_AllocatedMaterialPropertyBlocks.Clear();
		}

		internal bool IsEmpty()
		{
			if (m_AllocatedArrays.Count == 0)
			{
				return m_AllocatedMaterialPropertyBlocks.Count == 0;
			}
			return false;
		}

		internal T Get<T>() where T : class, new()
		{
			return SharedObjectPool<T>.Get();
		}

		internal void Release<T>(T value) where T : class, new()
		{
			SharedObjectPool<T>.Release(value);
		}

		internal void Cleanup()
		{
			m_AllocatedArrays.Clear();
			m_AllocatedMaterialPropertyBlocks.Clear();
			m_ArrayPool.Clear();
			DynamicArray<SharedObjectPoolBase>.Iterator enumerator = s_AllocatedPools.GetEnumerator();
			while (enumerator.MoveNext())
			{
				enumerator.Current.Clear();
			}
		}
	}
	[DebuggerDisplay("RenderPass: {name} (Index:{index} Async:{enableAsyncCompute})")]
	internal abstract class RenderGraphPass
	{
		public struct RandomWriteResourceInfo
		{
			public ResourceHandle h;

			public bool preserveCounterValue;
		}

		public List<ResourceHandle>[] resourceReadLists = new List<ResourceHandle>[3];

		public List<ResourceHandle>[] resourceWriteLists = new List<ResourceHandle>[3];

		public List<ResourceHandle>[] transientResourceList = new List<ResourceHandle>[3];

		public List<RendererListHandle> usedRendererListList = new List<RendererListHandle>();

		public List<(TextureHandle, int)> setGlobalsList = new List<(TextureHandle, int)>();

		public bool useAllGlobalTextures;

		public List<ResourceHandle> implicitReadsList = new List<ResourceHandle>();

		public string name { get; protected set; }

		public int index { get; protected set; }

		public RenderGraphPassType type { get; internal set; }

		public ProfilingSampler customSampler { get; protected set; }

		public bool enableAsyncCompute { get; protected set; }

		public bool allowPassCulling { get; protected set; }

		public bool allowGlobalState { get; protected set; }

		public bool enableFoveatedRasterization { get; protected set; }

		public TextureAccess depthAccess { get; protected set; }

		public TextureAccess[] colorBufferAccess { get; protected set; } = new TextureAccess[RenderGraph.kMaxMRTCount];

		public int colorBufferMaxIndex { get; protected set; } = -1;

		public bool hasShadingRateImage { get; protected set; }

		public TextureAccess shadingRateAccess { get; protected set; }

		public bool hasShadingRateStates { get; protected set; }

		public ShadingRateFragmentSize shadingRateFragmentSize { get; protected set; }

		public ShadingRateCombiner primitiveShadingRateCombiner { get; protected set; }

		public ShadingRateCombiner fragmentShadingRateCombiner { get; protected set; }

		public TextureAccess[] fragmentInputAccess { get; protected set; } = new TextureAccess[RenderGraph.kMaxMRTCount];

		public int fragmentInputMaxIndex { get; protected set; } = -1;

		public RandomWriteResourceInfo[] randomAccessResource { get; protected set; } = new RandomWriteResourceInfo[RenderGraph.kMaxMRTCount];

		public int randomAccessResourceMaxIndex { get; protected set; } = -1;

		public bool generateDebugData { get; protected set; }

		public bool allowRendererListCulling { get; protected set; }

		public abstract void Execute(InternalRenderGraphContext renderGraphContext);

		public abstract void Release(RenderGraphObjectPool pool);

		public abstract bool HasRenderFunc();

		public abstract int GetRenderFuncHash();

		public RenderGraphPass()
		{
			for (int i = 0; i < 3; i++)
			{
				resourceReadLists[i] = new List<ResourceHandle>();
				resourceWriteLists[i] = new List<ResourceHandle>();
				transientResourceList[i] = new List<ResourceHandle>();
			}
		}

		public void Clear()
		{
			name = "";
			index = -1;
			customSampler = null;
			for (int i = 0; i < 3; i++)
			{
				resourceReadLists[i].Clear();
				resourceWriteLists[i].Clear();
				transientResourceList[i].Clear();
			}
			usedRendererListList.Clear();
			setGlobalsList.Clear();
			useAllGlobalTextures = false;
			implicitReadsList.Clear();
			enableAsyncCompute = false;
			allowPassCulling = true;
			allowRendererListCulling = true;
			allowGlobalState = false;
			enableFoveatedRasterization = false;
			generateDebugData = true;
			colorBufferMaxIndex = -1;
			fragmentInputMaxIndex = -1;
			randomAccessResourceMaxIndex = -1;
			depthAccess = default(TextureAccess);
			hasShadingRateImage = false;
			hasShadingRateStates = false;
			shadingRateFragmentSize = ShadingRateFragmentSize.FragmentSize1x1;
			primitiveShadingRateCombiner = ShadingRateCombiner.Keep;
			fragmentShadingRateCombiner = ShadingRateCombiner.Keep;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public bool HasRenderAttachments()
		{
			if (!depthAccess.textureHandle.IsValid() && !colorBufferAccess[0].textureHandle.IsValid())
			{
				return colorBufferMaxIndex > 0;
			}
			return true;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public bool IsTransient(in ResourceHandle res)
		{
			for (int i = 0; i < transientResourceList[res.iType].Count; i++)
			{
				if (transientResourceList[res.iType][i].index == res.index)
				{
					return true;
				}
			}
			return false;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public bool IsWritten(in ResourceHandle res)
		{
			for (int i = 0; i < resourceWriteLists[res.iType].Count; i++)
			{
				if (resourceWriteLists[res.iType][i].index == res.index)
				{
					return true;
				}
			}
			return false;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public bool IsRead(in ResourceHandle res)
		{
			if (res.IsVersioned)
			{
				return resourceReadLists[res.iType].Contains(res);
			}
			for (int i = 0; i < resourceReadLists[res.iType].Count; i++)
			{
				if (resourceReadLists[res.iType][i].index == res.index)
				{
					return true;
				}
			}
			return false;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public bool IsAttachment(in TextureHandle res)
		{
			if (depthAccess.textureHandle.IsValid() && depthAccess.textureHandle.handle.index == res.handle.index)
			{
				return true;
			}
			for (int i = 0; i < colorBufferAccess.Length; i++)
			{
				if (colorBufferAccess[i].textureHandle.IsValid() && colorBufferAccess[i].textureHandle.handle.index == res.handle.index)
				{
					return true;
				}
			}
			return false;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public void AddResourceWrite(in ResourceHandle res)
		{
			resourceWriteLists[res.iType].Add(res);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public void AddResourceRead(in ResourceHandle res)
		{
			resourceReadLists[res.iType].Add(res);
		}

