		public override int GetHashCode()
		{
			HashFNV1A32 hashFNV1A = HashFNV1A32.Create();
			switch (sizeMode)
			{
			case TextureSizeMode.Explicit:
				hashFNV1A.Append(in width);
				hashFNV1A.Append(in height);
