			CompilerContextData.NativePassIterator enumerator4 = reference.NativePasses.GetEnumerator();
			while (enumerator4.MoveNext())
			{
				ref readonly NativePassData current8 = ref enumerator4.Current;
				List<int> list = new List<int>();
