		private void SetValue(int index, bool value)
		{
			RenderingLayerMask value2 = m_Field.GetValue();
			value2 = ((!value) ? ((RenderingLayerMask)((int)value2 & ~(1 << index))) : ((RenderingLayerMask)((int)value2 | (1 << index))));
			m_Field.SetValue(value2);
