		private void ChangeValue(bool fast, int multiplier)
		{
			long num = m_Field.GetValue();
			if (num != 0L || multiplier >= 0)
			{
				num += m_Field.incStep * ((!fast) ? 1 : m_Field.intStepMult) * multiplier;
				m_Field.SetValue((uint)num);
				UpdateValueLabel();
